   848→func (s *Server) waitForCacheSync(stop <-chan struct{}) bool {
   849→	start := time.Now()
   850→	log.Info("Waiting for caches to be synced")
   851→	if !kubelib.WaitForCacheSync("server", stop, s.cachesSynced) {
   852→		log.Errorf("Failed waiting for cache sync")
   853→		return false
   854→	}
   855→	log.Infof("All controller caches have been synced up in %v", time.Since(start))
   856→
   857→	// At this point, we know that all update events of the initial state-of-the-world have been
   858→	// received. We wait to ensure we have committed at least this many updates. This avoids a race
   859→	// condition where we are marked ready prior to updating the push context, leading to incomplete
   860→	// pushes.
   861→	expected := s.XDSServer.InboundUpdates.Load()
   862→	return kubelib.WaitForCacheSync("push context", stop, func() bool { return s.pushContextReady(expected) })
   863→}
   864→
   865→// pushContextReady indicates whether pushcontext has processed all inbound config updates.
   866→func (s *Server) pushContextReady(expected int64) bool {
   867→	committed := s.XDSServer.CommittedUpdates.Load()
   868→	if committed < expected {
   869→		log.Debugf("Waiting for pushcontext to process inbound updates, inbound: %v, committed : %v", expected, committed)
   870→		return false
   871→	}
