  1213→// maybeCreateCA creates and initializes the built-in CA if needed.
  1214→func (s *Server) maybeCreateCA(caOpts *caOptions) error {
  1215→	// CA signing certificate must be created only if CA is enabled.
  1216→	if features.EnableCAServer {
  1217→		log.Info("creating CA and initializing public key")
  1218→		var err error
  1219→		if useRemoteCerts.Get() {
  1220→			if err = s.loadCACerts(caOpts, LocalCertDir.Get()); err != nil {
  1221→				return fmt.Errorf("failed to load remote CA certs: %v", err)
  1222→			}
  1223→		}
  1224→		// May return nil, if the CA is missing required configs - This is not an error.
  1225→		// This is currently only used for K8S signing.
  1226→		if caOpts.ExternalCAType != "" {
  1227→			if s.RA, err = s.createIstioRA(caOpts); err != nil {
  1228→				return fmt.Errorf("failed to create RA: %v", err)
  1229→			}
  1230→		}
  1231→		// If K8S signs - we don't need to use the built-in istio CA.
  1232→		if !s.isK8SSigning() {
  1233→			if s.CA, err = s.createIstioCA(caOpts); err != nil {
  1234→				return fmt.Errorf("failed to create CA: %v", err)
  1235→			}
  1236→		}
  1237→	}
  1238→	return nil
  1239→}
