  1298→func (s *Server) addIstioCAToTrustBundle(args *PilotArgs) error {
  1299→	var err error
  1300→	if s.CA != nil {
  1301→		// If IstioCA is setup, derive trustAnchor directly from CA
  1302→		rootCerts := []string{string(s.CA.GetCAKeyCertBundle().GetRootCertPem())}
  1303→		err = s.workloadTrustBundle.UpdateTrustAnchor(&tb.TrustAnchorUpdate{
  1304→			TrustAnchorConfig: tb.TrustAnchorConfig{Certs: rootCerts},
  1305→			Source:            tb.SourceIstioCA,
  1306→		})
  1307→		if err != nil {
  1308→			log.Errorf("unable to add CA root from namespace %s as trustAnchor", args.Namespace)
  1309→			return err
  1310→		}
  1311→		return nil
  1312→	}
  1313→	return nil
  1314→}
