  1098→// hasCustomTLSCerts returns the tls cert paths, used both if custom TLS certificates are configured via args or by mounting in well known.
  1099→// while tls args should still take precedence the aim is to encourage loading the DNS tls cert in the well known path locations.
  1100→func hasCustomTLSCerts(tlsOptions TLSOptions) (ok bool, tlsCertPath, tlsKeyPath, caCertPath string) {
  1101→	// load from tls args as priority
  1102→	if hasCustomTLSCertArgs(tlsOptions) {
  1103→		return true, tlsOptions.CertFile, tlsOptions.KeyFile, tlsOptions.CaCertFile
  1104→	}
  1105→
  1106→	if ok = checkPathsExist(constants.DefaultPilotTLSCert, constants.DefaultPilotTLSKey, constants.DefaultPilotTLSCaCert); ok {
  1107→		tlsCertPath = constants.DefaultPilotTLSCert
  1108→		tlsKeyPath = constants.DefaultPilotTLSKey
  1109→		caCertPath = constants.DefaultPilotTLSCaCert
  1110→		return ok, tlsCertPath, tlsKeyPath, caCertPath
  1111→	}
  1112→
  1113→	if ok = checkPathsExist(constants.DefaultPilotTLSCert, constants.DefaultPilotTLSKey, constants.DefaultPilotTLSCaCertAlternatePath); ok {
  1114→		tlsCertPath = constants.DefaultPilotTLSCert
  1115→		tlsKeyPath = constants.DefaultPilotTLSKey
  1116→		caCertPath = constants.DefaultPilotTLSCaCertAlternatePath
  1117→		return ok, tlsCertPath, tlsKeyPath, caCertPath
  1118→	}
  1119→
  1120→	return ok, tlsCertPath, tlsKeyPath, caCertPath
  1121→}
