  1316→func (s *Server) initWorkloadTrustBundle(args *PilotArgs) error {
  1317→	var err error
  1318→
  1319→	if !features.MultiRootMesh {
  1320→		return nil
  1321→	}
  1322→
  1323→	s.workloadTrustBundle.UpdateCb(func() {
  1324→		pushReq := &model.PushRequest{
  1325→			Full:   true,
  1326→			Reason: model.NewReasonStats(model.GlobalUpdate),
  1327→			Forced: true,
  1328→		}
  1329→		s.XDSServer.ConfigUpdate(pushReq)
  1330→	})
  1331→
  1332→	s.addStartFunc("remote trust anchors", func(stop <-chan struct{}) error {
  1333→		go s.workloadTrustBundle.ProcessRemoteTrustAnchors(stop, tb.RemoteDefaultPollPeriod)
  1334→		return nil
  1335→	})
  1336→
  1337→	// MeshConfig: Add initial roots
  1338→	err = s.workloadTrustBundle.AddMeshConfigUpdate(s.environment.Mesh())
  1339→	if err != nil {
  1340→		return err
  1341→	}
  1342→
  1343→	// MeshConfig:Add callback for mesh config update
  1344→	s.environment.AddMeshHandler(func() {
  1345→		_ = s.workloadTrustBundle.AddMeshConfigUpdate(s.environment.Mesh())
  1346→	})
  1347→
  1348→	err = s.addIstioCAToTrustBundle(args)
  1349→	if err != nil {
  1350→		return err
  1351→	}
  1352→
  1353→	// IstioRA: Explicitly add roots corresponding to RA
  1354→	if s.RA != nil {
  1355→		// Implicitly add the Istio RA certificates to the Workload Trust Bundle
  1356→		rootCerts := []string{string(s.RA.GetCAKeyCertBundle().GetRootCertPem())}
  1357→		err = s.workloadTrustBundle.UpdateTrustAnchor(&tb.TrustAnchorUpdate{
  1358→			TrustAnchorConfig: tb.TrustAnchorConfig{Certs: rootCerts},
  1359→			Source:            tb.SourceIstioRA,
  1360→		})
  1361→		if err != nil {
  1362→			log.Errorf("fatal: unable to add RA root as trustAnchor")
  1363→			return err
  1364→		}
  1365→	}
  1366→	log.Infof("done initializing workload trustBundle")
  1367→	return nil
  1368→}
