   889→// initRegistryEventHandlers sets up event handlers for config and service updates
   890→func (s *Server) initRegistryEventHandlers() {
   891→	log.Info("initializing registry event handlers")
   892→	// Flush cached discovery responses whenever services configuration change.
   893→	serviceHandler := func(prev, curr *model.Service, event model.Event) {
   894→		pushReq := &model.PushRequest{
   895→			Full:           true,
   896→			ConfigsUpdated: sets.New(model.ConfigKey{Kind: kind.ServiceEntry, Name: string(curr.Hostname), Namespace: curr.Attributes.Namespace}),
   897→			Reason:         model.NewReasonStats(model.ServiceUpdate),
   898→		}
   899→		s.XDSServer.ConfigUpdate(pushReq)
   900→	}
   901→	s.ServiceController().AppendServiceHandler(serviceHandler)
   902→
   903→	if s.configController != nil {
   904→		configHandler := func(prev config.Config, curr config.Config, event model.Event) {
   905→			log.Debugf("Handle event %s for configuration %s", event, curr.Key())
   906→			// For update events, trigger push only if spec has changed.
   907→			if event == model.EventUpdate && !needsPush(prev, curr) {
   908→				log.Debugf("skipping push for %s as spec has not changed", prev.Key())
   909→				return
   910→			}
   911→			pushReq := &model.PushRequest{
   912→				Full:           true,
   913→				ConfigsUpdated: sets.New(model.ConfigKey{Kind: gvk.MustToKind(curr.GroupVersionKind), Name: curr.Name, Namespace: curr.Namespace}),
   914→				Reason:         model.NewReasonStats(model.ConfigUpdate),
   915→			}
   916→			s.XDSServer.ConfigUpdate(pushReq)
   917→		}
   918→		schemas := collections.Pilot.All()
   919→		if features.EnableGatewayAPI {
   920→			schemas = collections.PilotGatewayAPI().All()
   921→		}
   922→		for _, schema := range schemas {
   923→			// This resource type was handled in external/servicediscovery.go, no need to rehandle here.
   924→			if schema.GroupVersionKind() == gvk.ServiceEntry {
   925→				continue
   926→			}
   927→			if schema.GroupVersionKind() == gvk.WorkloadEntry {
   928→				continue
   929→			}
   930→			if schema.GroupVersionKind() == gvk.WorkloadGroup {
   931→				continue
   932→			}
   933→			// Already handled by gateway controller
   934→			if schema.GroupVersionKind().Group == gvk.KubernetesGateway.Group {
   935→				continue
   936→			}
   937→
   938→			s.configController.RegisterEventHandler(schema.GroupVersionKind(), configHandler)
   939→		}
   940→	}
   941→}
