  1018→func getDNSNames(args *PilotArgs, host string) []string {
  1019→	// Append custom hostname if there is any
  1020→	customHost := features.IstiodServiceCustomHost
  1021→	var cHosts []string
  1022→
  1023→	if customHost != "" {
  1024→		cHosts = strings.Split(customHost, ",")
  1025→	}
  1026→	sans := sets.New(cHosts...)
  1027→	sans.Insert(host)
  1028→	// The first is the recommended one, also used by Apiserver for webhooks.
  1029→	// add a few known hostnames
  1030→	knownHosts := []string{"istiod", "istiod-remote", "istio-pilot"}
  1031→	// In some conditions, pilot address for sds is different from other xds,
  1032→	// like multi-cluster primary-remote mode with revision.
  1033→	if args.Revision != "" && args.Revision != "default" {
  1034→		knownHosts = append(knownHosts, "istiod"+"-"+args.Revision)
  1035→	}
  1036→	knownSans := make([]string, 0, 2*len(knownHosts))
  1037→	for _, altName := range knownHosts {
  1038→		knownSans = append(knownSans,
  1039→			fmt.Sprintf("%s.%s.svc", altName, args.Namespace))
  1040→	}
  1041→	sans.InsertAll(knownSans...)
  1042→	dnsNames := sets.SortedList(sans)
  1043→	log.Infof("Discover server subject alt names: %v", dnsNames)
  1044→	return dnsNames
  1045→}
