  1047→// createPeerCertVerifier creates a SPIFFE certificate verifier with the current istiod configuration.
  1048→func (s *Server) createPeerCertVerifier(tlsOptions TLSOptions, trustDomain string) (*spiffe.PeerCertVerifier, error) {
  1049→	customTLSCertsExists, _, _, caCertPath := hasCustomTLSCerts(tlsOptions)
  1050→	if !customTLSCertsExists && s.CA == nil && !s.isK8SSigning() {
  1051→		// Running locally without configured certs - no TLS mode
  1052→		return nil, nil
  1053→	}
  1054→	peerCertVerifier := spiffe.NewPeerCertVerifier()
  1055→	var rootCertBytes []byte
  1056→	var err error
  1057→	if caCertPath != "" {
  1058→		if rootCertBytes, err = os.ReadFile(caCertPath); err != nil {
  1059→			return nil, err
  1060→		}
  1061→	} else {
  1062→		if s.RA != nil {
  1063→			if strings.HasPrefix(features.PilotCertProvider, constants.CertProviderKubernetesSignerPrefix) {
  1064→				signerName := strings.TrimPrefix(features.PilotCertProvider, constants.CertProviderKubernetesSignerPrefix)
  1065→				caBundle, _ := s.RA.GetRootCertFromMeshConfig(signerName)
  1066→				rootCertBytes = append(rootCertBytes, caBundle...)
  1067→			} else {
  1068→				rootCertBytes = append(rootCertBytes, s.RA.GetCAKeyCertBundle().GetRootCertPem()...)
  1069→			}
  1070→		}
  1071→		if s.CA != nil {
  1072→			rootCertBytes = append(rootCertBytes, s.CA.GetCAKeyCertBundle().GetRootCertPem()...)
  1073→		}
  1074→	}
  1075→
  1076→	if len(rootCertBytes) != 0 {
  1077→		// TODO: trustDomain here is static and will not update if it dynamically changes in mesh config
  1078→		err := peerCertVerifier.AddMappingFromPEM(trustDomain, rootCertBytes)
  1079→		if err != nil {
  1080→			return nil, fmt.Errorf("add root CAs into peerCertVerifier failed: %v", err)
  1081→		}
  1082→	}
  1083→
  1084→	return peerCertVerifier, nil
  1085→}
