  1087→func checkPathsExist(paths ...string) bool {
  1088→	for _, path := range paths {
  1089→		fInfo, err := os.Stat(path)
  1090→
  1091→		if err != nil || fInfo.IsDir() {
  1092→			return false
  1093→		}
  1094→	}
  1095→	return true
  1096→}
