  1241→// Returns true to indicate the K8S multicluster controller should enable replication of
  1242→// root certificates to config maps in namespaces.
  1243→func (s *Server) shouldStartNsController() bool {
  1244→	if s.isK8SSigning() {
  1245→		// Need to distribute the roots from MeshConfig
  1246→		return true
  1247→	}
  1248→	if s.CA == nil {
  1249→		return false
  1250→	}
  1251→
  1252→	// For no CA we don't distribute it either, as there is no cert
  1253→	if features.PilotCertProvider == constants.CertProviderNone {
  1254→		return false
  1255→	}
  1256→
  1257→	return true
  1258→}
