  1260→// StartCA starts the CA or RA server if configured.
  1261→func (s *Server) startCA(caOpts *caOptions) {
  1262→	if s.CA == nil && s.RA == nil {
  1263→		return
  1264→	}
  1265→	// init the RA server if configured, else start init CA server
  1266→	if s.RA != nil {
  1267→		log.Infof("initializing CA server with RA")
  1268→		s.initCAServer(s.RA, caOpts)
  1269→	} else if s.CA != nil {
  1270→		log.Infof("initializing CA server with IstioD CA")
  1271→		s.initCAServer(s.CA, caOpts)
  1272→	}
  1273→	s.addStartFunc("ca", func(stop <-chan struct{}) error {
  1274→		grpcServer := s.secureGrpcServer
  1275→		if s.secureGrpcServer == nil {
  1276→			grpcServer = s.grpcServer
  1277→		}
  1278→		log.Infof("starting CA server")
  1279→		s.RunCA(grpcServer)
  1280→		return nil
  1281→	})
  1282→}
